fn max_subarray(v: i64, n: i64) -> i64 = {
    let best = vec_get(v, 0);
    let cur = best;
    let i = 1;
    while i < n {
        let x = vec_get(v, i);
        cur = if cur + x > x { cur + x } else { x };
        best = if cur > best { cur } else { best };
        i = i + 1
    };
    best
};

